class Solution:
    def maxSubstringLength(self, s, k):
        if k == 0:
            return True
        n = len(s)
        first = {}
        last = {}
        for i, ch in enumerate(s):
            if ch not in first:
                first[ch] = i
            last[ch] = i
        valid_intervals = []
        for l in range(n):
            for r in range(l, n):
                if l == 0 and r == n - 1:
                    continue
                chars_here = set(s[l:r + 1])
                ok = True
                for ch in chars_here:
                    if first[ch] < l or last[ch] > r:
                        ok = False
                        break
                if ok:
                    valid_intervals.append((r, l))
        valid_intervals.sort()
        count = 0
        last_end = -1
        for end, start in valid_intervals:
            if start > last_end:
                count += 1
                last_end = end
        return k <= count

