class Solution:
    def maxSubstringLength(self, s, k):
        n = len(s)
        if k == 0:
            return True
        first = {}
        last = {}
        for i, ch in enumerate(s):
            if ch not in first:
                first[ch] = i
            last[ch] = i

        closures = []
        for c in first:
            l, r = first[c], last[c]
            while True:
                if l == 0 and r == n - 1:
                    break
                changed = False
                for ch2 in set(s[l:r + 1]):
                    fl, la = first[ch2], last[ch2]
                    if fl < l or la > r:
                        l = min(l, fl)
                        r = max(r, la)
                        changed = True
                if not changed:
                    break
            closures.append((l, r))

        valid = set()
        for l, r in closures:
            if not (l == 0 and r == n - 1):
                valid.add((l, r))
        valid_list = list(valid)

        leaves = 0
        for i, (l1, r1) in enumerate(valid_list):
            is_leaf = True
            for j, (l2, r2) in enumerate(valid_list):
                if i == j:
                    continue
                if l1 <= l2 and r2 <= r1 and (l2 > l1 or r2 < r1):
                    is_leaf = False
                    break
            if is_leaf:
                leaves += 1
        return k <= leaves

