var maxSubstringLength = function(s, k) {
    const n = s.length;
    if (k === 0) return true;
    const first = new Map();
    const last = new Map();
    for (let i = 0; i < n; i++) {
        const ch = s[i];
        if (!first.has(ch)) first.set(ch, i);
        last.set(ch, i);
    }

    const closureList = [];
    for (const c of first.keys()) {
        let l = first.get(c), r = last.get(c);
        while (true) {
            if (l === 0 && r === n - 1) break;
            let changed = false;
            const seen = new Set();
            for (let i = l; i <= r; i++) seen.add(s[i]);
            for (const ch2 of seen) {
                const fl = first.get(ch2), la = last.get(ch2);
                if (fl < l || la > r) {
                    l = Math.min(l, fl);
                    r = Math.max(r, la);
                    changed = true;
                }
            }
            if (!changed) break;
        }
        closureList.push([l, r]);
    }

    const validSet = [];
    const seenKeys = new Set();
    for (const [l, r] of closureList) {
        if (l === 0 && r === n - 1) continue;
        const key = l + ',' + r;
        if (!seenKeys.has(key)) {
            seenKeys.add(key);
            validSet.push([l, r]);
        }
    }

    let leaves = 0;
    for (let i = 0; i < validSet.length; i++) {
        const [l1, r1] = validSet[i];
        let isLeaf = true;
        for (let j = 0; j < validSet.length; j++) {
            if (i === j) continue;
            const [l2, r2] = validSet[j];
            if (l1 <= l2 && r2 <= r1 && (l2 > l1 || r2 < r1)) {
                isLeaf = false;
                break;
            }
        }
        if (isLeaf) leaves++;
    }
    return k <= leaves;
};
